1	<script lang="ts">
2		import { gql } from 'graphql-request';
3		import { createClient } from '$lib/gql/client';
4		import { invalidateAll } from '$app/navigation';
5		import { nodeStore } from '$lib/stores/node.svelte';
6		import { X, UserPlus, UserMinus, Pencil, Trash2, Copy, Check } from 'lucide-svelte';
7		import BeadForm from './BeadForm.svelte';
8		import TypedConfirmDialog from './TypedConfirmDialog.svelte';
9	
10		interface Dependency {
11			issueId: string;
12			dependsOnId: string;
13			type: string;
14			createdAt: string | null;
15			createdBy: string | null;
16		}
17	
18		interface Bead {
19			id: string;
20			title: string;
21			status: string;
22			priority: number;
23			issueType: string;
24			owner: string | null;
25			createdAt: string;
26			createdBy: string | null;
27			updatedAt: string;
28			labels: string[] | null;
29			parent: string | null;
30			description: string | null;
31			acceptance: string | null;
32			notes: string | null;
33			dependencies: Dependency[] | null;
34			childCount?: number;
35		}
36	
37		interface BeadExecutionRow {
38			id: string;
39			verdict: string | null;
40			harness: string | null;
41			createdAt: string;
42			durationMs: number | null;
43			costUsd: number | null;
44		}
45	
46		interface BeadRunRow {
47			id: string;
48			layer: string;
49			status: string;
50			harness: string | null;
51			startedAt: string | null;
52			durationMs: number | null;
53		}
54	
55		let {
56			bead: initialBead,
57			onClose,
58			executions = [],
59			runs = [],
60			nodeId = '',
61			projectId = ''
62		}: {
63			bead: Bead;
64			onClose: () => void;
65			executions?: BeadExecutionRow[];
66			runs?: BeadRunRow[];
67			nodeId?: string;
68			projectId?: string;
69		} = $props();
70	
71		function executionHref(executionId: string): string {
72			return `/nodes/${nodeId}/projects/${projectId}/executions/${executionId}`;
73		}
74	
75		function runHref(runId: string): string {
76			return `/nodes/${nodeId}/projects/${projectId}/runs/${runId}`;
77		}
78	
79		function fmtExecDate(iso: string): string {
80			try {
81				return new Date(iso).toLocaleString();
82			} catch {
83				return iso;
84			}
85		}
86	
87		let bead = $state<Bead>({ ...initialBead });
88		let editing = $state(false);
89		let busy = $state(false);
90		let actionError = $state<string | null>(null);
91		let deleteDialogOpen = $state(false);
92		let cascadeToChildren = $state(false);
93		let deleteButton = $state<HTMLButtonElement | null>(null);
94		let idCopied = $state(false);
95		let idCopyTimer: ReturnType<typeof setTimeout> | null = null;
96		const hasChildBeads = $derived((bead.childCount ?? 0) > 0);
97	
98		async function handleCopyId() {
99			try {
100				await navigator.clipboard.writeText(bead.id);
101				idCopied = true;
102				if (idCopyTimer) clearTimeout(idCopyTimer);
103				idCopyTimer = setTimeout(() => {
104					idCopied = false;
105				}, 1500);
106			} catch {
107				// clipboard may be unavailable; silently fail
108			}
109		}
110	
111		const CLAIM_MUTATION = gql`
112			mutation BeadClaim($id: ID!, $assignee: String!) {
113				beadClaim(id: $id, assignee: $assignee) {
114					id
115					title
116					status
117					priority
118					issueType
119					owner
120					createdAt
121					createdBy
122					updatedAt
123					labels
124					parent
125					description
126					acceptance
127					notes
128					dependencies {
129						issueId
130						dependsOnId
131						type
132						createdAt
133						createdBy
134					}
135				}
136			}
137		`;
138	
139		const UNCLAIM_MUTATION = gql`
140			mutation BeadUnclaim($id: ID!) {
141				beadUnclaim(id: $id) {
142					id
143					title
144					status
145					priority
146					issueType
147					owner
148					createdAt
149					createdBy
150					updatedAt
151					labels
152					parent
153					description
154					acceptance
155					notes
156					dependencies {
157						issueId
158						dependsOnId
159						type
160						createdAt
161						createdBy
162					}
163				}
164			}
165		`;
166	
167		const CLOSE_MUTATION = gql`
168			mutation BeadClose($id: ID!, $reason: String) {
169				beadClose(id: $id, reason: $reason) {
170					id
171					title
172					status
173					priority
174					issueType
175					owner
176					createdAt
177					createdBy
178					updatedAt
179					labels
180					parent
181					description
182					acceptance
183					notes
184					dependencies {
185						issueId
186						dependsOnId
187						type
188						createdAt
189						createdBy
190					}
191				}
192			}
193		`;
194	
195		async function handleClaim() {
196			busy = true;
197			actionError = null;
198			try {
199				const client = createClient();
200				const assignee = nodeStore.value?.name ?? 'user';
201				const result = await client.request<{ beadClaim: Bead }>(CLAIM_MUTATION, {
202					id: bead.id,
203					assignee
204				});
205				bead = result.beadClaim;
206				invalidateAll();
207			} catch (e) {
208				actionError = e instanceof Error ? e.message : 'Claim failed';
209			} finally {
210				busy = false;
211			}
212		}
213	
214		async function handleUnclaim() {
215			busy = true;
216			actionError = null;
217			try {
218				const client = createClient();
219				const result = await client.request<{ beadUnclaim: Bead }>(UNCLAIM_MUTATION, {
220					id: bead.id
221				});
222				bead = result.beadUnclaim;
223				invalidateAll();
224			} catch (e) {
225				actionError = e instanceof Error ? e.message : 'Unclaim failed';
226			} finally {
227				busy = false;
228			}
229		}
230	
231		function openDeleteDialog() {
232			cascadeToChildren = false;
233			deleteDialogOpen = true;
234		}
235	
236		async function handleDeleteConfirm() {
237			busy = true;
238			actionError = null;
239			try {
240				const client = createClient();
241				await client.request<{ beadClose: Bead }>(CLOSE_MUTATION, {
242					id: bead.id,
243					reason: 'deleted via UI'
244				});
245				await invalidateAll();
246				onClose();
247			} catch (e) {
248				actionError = e instanceof Error ? e.message : 'Delete failed';
249			} finally {
250				busy = false;
251			}
252		}
253	
254		function statusClass(status: string): string {
255			switch (status) {
256				case 'open':
257					return 'text-accent-lever dark:text-dark-accent-lever';
258				case 'in-progress':
259					return 'text-accent-load dark:text-dark-accent-load';
260				case 'closed':
261					return 'text-status-closed dark:text-status-closed';
262				case 'blocked':
263					return 'text-error dark:text-dark-error';
264				default:
265					return 'text-fg-muted dark:text-dark-fg-muted';
266			}
267		}
268	</script>
269	
270	<!-- Right-side detail panel -->
271	<div
272		class="fixed top-0 right-0 z-50 flex h-full w-full max-w-xl flex-col bg-bg-elevated shadow-xl dark:bg-dark-bg-canvas"
273		style="max-width: 36rem;"
274	>
275		<!-- Header -->
276		<div
277			class="flex shrink-0 items-center justify-between border-b border-border-line px-6 py-4 dark:border-dark-border-line"
278		>
279			<div class="flex min-w-0 items-center gap-3">
280				<span
281					title={bead.id}
282					data-testid="bead-detail-id"
283					class="min-w-0 truncate font-mono-code text-xs text-fg-muted dark:text-dark-fg-muted"
284					>{bead.id}</span
285				>
286				<button
287					type="button"
288					onclick={handleCopyId}
289					aria-label="Copy bead id"
290					data-testid="bead-detail-copy-id"
291					class="shrink-0 rounded-none p-1 text-fg-muted hover:bg-bg-canvas hover:text-fg-ink dark:hover:bg-dark-bg-elevated dark:hover:text-dark-fg-ink"
292				>
293					{#if idCopied}
294						<Check class="h-3.5 w-3.5 text-status-closed" />
295					{:else}
296						<Copy class="h-3.5 w-3.5" />
297					{/if}
298				</button>
299				<span class="shrink-0 font-medium {statusClass(bead.status)}">{bead.status}</span>
300				{#if bead.owner}
301					<span class="shrink-0 truncate text-xs text-fg-muted dark:text-dark-fg-muted">@ {bead.owner}</span>
302				{/if}
303			</div>
304			<div class="ml-3 flex shrink-0 items-center gap-2">
305				{#if !editing}
306					{#if bead.status === 'open' || bead.status === 'blocked'}
307						<button
308							onclick={handleClaim}
309							disabled={busy}
310							class="flex items-center gap-1.5 rounded-none bg-accent-lever px-3 py-1.5 text-sm font-medium text-white hover:bg-accent-lever/90 disabled:cursor-not-allowed disabled:opacity-50"
311						>
312							<UserPlus class="h-3.5 w-3.5" />
313							Claim
314						</button>
315					{:else if bead.status === 'in-progress'}
316						<button
317							onclick={handleUnclaim}
318							disabled={busy}
319							class="flex items-center gap-1.5 rounded-none border border-border-line px-3 py-1.5 text-sm font-medium text-fg-muted hover:bg-bg-surface disabled:cursor-not-allowed disabled:opacity-50 dark:border-dark-border-line dark:text-dark-fg-ink dark:hover:bg-dark-bg-elevated"
320						>
321							<UserMinus class="h-3.5 w-3.5" />
322							Unclaim
323						</button>
324					{/if}
325					<button
326						onclick={() => (editing = true)}
327						disabled={busy}
328						class="flex items-center gap-1.5 rounded-none border border-border-line px-3 py-1.5 text-sm font-medium text-fg-muted hover:bg-bg-surface dark:border-dark-border-line dark:text-dark-fg-ink dark:hover:bg-dark-bg-elevated"
329					>
330						<Pencil class="h-3.5 w-3.5" />
331						Edit
332					</button>
333					<button
334						bind:this={deleteButton}
335						onclick={openDeleteDialog}
336						disabled={busy}
337						class="flex items-center gap-1.5 rounded-none border border-error/30 px-3 py-1.5 text-sm font-medium text-error hover:bg-error/10 disabled:cursor-not-allowed disabled:opacity-50 dark:border-dark-error/30 dark:text-dark-error dark:hover:bg-dark-error/10"
338					>
339						<Trash2 class="h-3.5 w-3.5" />
340						Delete
341					</button>
342				{/if}
343				<button
344					onclick={onClose}
345					class="rounded-none p-1.5 text-fg-muted hover:bg-bg-canvas dark:text-dark-fg-muted dark:hover:bg-dark-bg-elevated"
346					aria-label="Close panel"
347				>
348					<X class="h-4 w-4" />
349				</button>
350			</div>
351		</div>
352	
353		<!-- Action error banner -->
354		{#if actionError}
355			<div
356				class="shrink-0 border-b border-error/30 bg-error/10 px-6 py-2 text-sm text-error dark:border-dark-error/30 dark:bg-dark-error/10 dark:text-dark-error"
357			>
358				{actionError}
359			</div>
360		{/if}
361	
362		<!-- Scrollable content -->
363		<div class="flex-1 overflow-auto p-6">
364			{#if editing}
365				{#key bead?.id}
366					<BeadForm
367						{bead}
368						onSuccess={(updated) => {
369							bead = updated;
370							editing = false;
371						}}
372						onCancel={() => (editing = false)}
373					/>
374				{/key}
375			{:else}
376				<!-- Read mode -->
377				<h2 class="mb-5 text-xl font-semibold text-fg-ink dark:text-dark-fg-ink">{bead.title}</h2>
378	
379				<dl class="space-y-4 text-sm">
380					<div class="grid grid-cols-2 gap-4">
381						<div>
382							<dt
383								class="text-xs font-medium tracking-wide text-fg-muted uppercase dark:text-dark-fg-muted"
384							>
385								Priority
386							</dt>
387							<dd class="mt-1 text-fg-ink dark:text-dark-fg-ink">{bead.priority}</dd>
388						</div>
389						<div>
390							<dt
391								class="text-xs font-medium tracking-wide text-fg-muted uppercase dark:text-dark-fg-muted"
392							>
393								Type
394							</dt>
395							<dd class="mt-1 text-fg-ink dark:text-dark-fg-ink">{bead.issueType || '—'}</dd>
396						</div>
397						{#if bead.parent}
398							<div class="col-span-2">
399								<dt
400									class="text-xs font-medium tracking-wide text-fg-muted uppercase dark:text-dark-fg-muted"
401								>
402									Parent
403								</dt>
404								<dd class="mt-1 font-mono-code text-xs text-fg-muted dark:text-dark-fg-muted">{bead.parent}</dd>
405							</div>
406						{/if}
407					</div>
408	
409					{#if bead.labels && bead.labels.length > 0}
410						<div>
411							<dt
412								class="text-xs font-medium tracking-wide text-fg-muted uppercase dark:text-dark-fg-muted"
413							>
414								Labels
415							</dt>
416							<dd class="mt-1 flex flex-wrap gap-1">
417								{#each bead.labels as label}
418									<span
419										class="rounded-none bg-bg-canvas px-2 py-0.5 text-xs text-fg-muted dark:bg-dark-bg-elevated dark:text-dark-fg-ink"
420										>{label}</span
421									>
422								{/each}
423							</dd>
424						</div>
425					{/if}
426	
427					{#if bead.description}
428						<div>
429							<dt
430								class="text-xs font-medium tracking-wide text-fg-muted uppercase dark:text-dark-fg-muted"
431							>
432								Description
433							</dt>
434							<dd class="mt-1 whitespace-pre-wrap text-fg-muted dark:text-dark-fg-ink">
435								{bead.description}
436							</dd>
437						</div>
438					{/if}
439	
440					{#if bead.acceptance}
441						<div>
442							<dt
443								class="text-xs font-medium tracking-wide text-fg-muted uppercase dark:text-dark-fg-muted"
444							>
445								Acceptance
446							</dt>
447							<dd class="mt-1 whitespace-pre-wrap text-fg-muted dark:text-dark-fg-ink">
448								{bead.acceptance}
449							</dd>
450						</div>
451					{/if}
452	
453					{#if bead.notes}
454						<div>
455							<dt
456								class="text-xs font-medium tracking-wide text-fg-muted uppercase dark:text-dark-fg-muted"
457							>
458								Notes
459							</dt>
460							<dd class="mt-1 whitespace-pre-wrap text-fg-muted dark:text-dark-fg-ink">{bead.notes}</dd>
461						</div>
462					{/if}
463	
464					{#if runs.length > 0}
465						<div data-testid="bead-linked-runs">
466							<dt class="text-xs font-medium tracking-wide text-fg-muted uppercase dark:text-dark-fg-muted">
467								Linked Runs ({runs.length})
468							</dt>
469							<dd class="mt-1 space-y-1">
470								{#each runs as run (run.id)}
471									<a
472										href={runHref(run.id)}
473										data-testid="bead-linked-run"
474										class="flex items-center justify-between rounded-none border border-border-line px-2 py-1 text-xs hover:bg-bg-surface dark:border-dark-border-line dark:hover:bg-dark-bg-elevated"
475									>
476										<span class="flex items-center gap-2">
477											<span class="font-mono-code text-accent-lever dark:text-dark-accent-lever">{run.id}</span>
478											<span class="rounded-none border border-border-line bg-bg-canvas px-1 py-0.5 text-[10px] uppercase text-fg-muted dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-muted">
479												{run.layer}
480											</span>
481											<span class="rounded-none border border-border-line bg-bg-canvas px-1 py-0.5 text-[10px] uppercase text-fg-muted dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-muted">
482												{run.status}
483											</span>
484											{#if run.harness}
485												<span class="font-mono-code text-fg-muted dark:text-dark-fg-muted">{run.harness}</span>
486											{/if}
487										</span>
488										<span class="text-fg-muted dark:text-dark-fg-muted">
489											{run.startedAt ? new Date(run.startedAt).toLocaleString() : '—'}
490										</span>
491									</a>
492								{/each}
493							</dd>
494						</div>
495					{/if}
496	
497					{#if executions.length > 0}
498						<div data-testid="bead-executions">
499							<dt class="text-xs font-medium tracking-wide text-fg-muted uppercase dark:text-dark-fg-muted">
500								Executions ({executions.length})
501							</dt>
502							<dd class="mt-1 space-y-1">
503								{#each executions as exec (exec.id)}
504									<a
505										href={executionHref(exec.id)}
506										class="flex items-center justify-between rounded-none border border-border-line px-2 py-1 text-xs hover:bg-bg-surface dark:border-dark-border-line dark:hover:bg-dark-bg-elevated"
