511												<span class="rounded-none border border-border-line bg-bg-canvas px-1 py-0.5 text-[10px] uppercase text-fg-muted dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-muted">
512													{exec.verdict}
513												</span>
514											{/if}
515										</span>
516										<span class="text-fg-muted dark:text-dark-fg-muted">{fmtExecDate(exec.createdAt)}</span>
517									</a>
518								{/each}
519							</dd>
520						</div>
521					{/if}
522	
523					{#if bead.dependencies && bead.dependencies.length > 0}
524						<div>
525							<dt
526								class="text-xs font-medium tracking-wide text-fg-muted uppercase dark:text-dark-fg-muted"
527							>
528								Dependencies
529							</dt>
530							<dd class="mt-1 space-y-1">
531								{#each bead.dependencies as dep}
532									<div class="font-mono-code text-xs text-fg-muted dark:text-dark-fg-muted">
533										{dep.dependsOnId}
534										<span class="text-fg-muted dark:text-dark-fg-muted">({dep.type})</span>
535									</div>
536								{/each}
537							</dd>
538						</div>
539					{/if}
540	
541					<div
542						class="border-t border-border-line pt-4 text-xs text-fg-muted dark:border-dark-border-line dark:text-dark-fg-muted"
543					>
544						<div>
545							Created: {new Date(bead.createdAt).toLocaleString()}{bead.createdBy
546								? ` by ${bead.createdBy}`
547								: ''}
548						</div>
549						<div>Updated: {new Date(bead.updatedAt).toLocaleString()}</div>
550					</div>
551				</dl>
552			{/if}
553		</div>
554	
555		<TypedConfirmDialog
556			bind:open={deleteDialogOpen}
557			actionLabel="Delete bead"
558			title="Delete bead"
559			expectedText={bead.id}
560			expectedLabel="bead id"
561			destructive
562			confirmDisabled={busy}
563			returnFocusTo={deleteButton}
564			onConfirm={handleDeleteConfirm}
565		>
566			{#snippet summary()}
567				<span>
