576					<input
577						type="checkbox"
578						bind:checked={cascadeToChildren}
579						class="mt-1 h-4 w-4 rounded-none border-error/50 text-error focus:ring-error dark:border-dark-error/50 dark:bg-dark-bg-elevated"
580					/>
581					<span>
582						<span class="block font-medium">Cascade to child beads</span>
583						<span class="block text-xs text-error dark:text-dark-error">
584							Apply the delete intent to {bead.childCount} child {bead.childCount === 1
585								? 'bead'
586								: 'beads'}.
587						</span>
588					</span>
589				</label>
590			{/if}
591		</TypedConfirmDialog>
592	</div>
593
